// ─── Inicialização do Hono ──────────────────────────────────────────────────

const app = new Hono<{ Bindings: Bindings; Variables: Variables }>();

app.use('*', secureHeaders());
app.use('*', cors({
  origin: (origin) => {
    if (origin && (origin.endsWith('ness.workers.dev') || origin.startsWith('http://localhost'))) {
      return origin;
    }
    return null;
  }
}));

app.use('/api/v1/*', async (c, next) => {
  const path = new URL(c.req.url).pathname;
  if (path.startsWith('/api/v1/auth/login') || path.startsWith('/api/v1/auth/setup') || path.startsWith('/api/v1/auditor/')) {
    return next();
  }
  
  const authHeader = c.req.header('Authorization');
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return c.json({ error: 'Unauthorized: Missing or invalid token' }, 401);
  }
  
  const token = authHeader.split(' ')[1];
  const userJson = await c.env.SESSIONS.get(token);
  
  if (!userJson) {
    return c.json({ error: 'Unauthorized: Invalid or expired token' }, 401);
  }
  
  c.set('user', JSON.parse(userJson));
  await next();
});

// ─── Helpers de Auth ────────────────────────────────────────────────────────

async function hashPassword(password: string): Promise<string> {
  const msgBuffer = new TextEncoder().encode(password);
  const hashBuffer = await crypto.subtle.digest('SHA-256', msgBuffer);
  const hashArray = Array.from(new Uint8Array(hashBuffer));
  return hashArray.map(b => b.toString(16).padStart(2, '0')).join('');
}

// ─── Helper: gravar log de auditoria ────────────────────────────────────────

async function logAudit(
  db: D1Database,
  action: string,
  actor: string,
  details: string,
  justification: string = '',
  ip: string = ''
) {
  await db
    .prepare(
      `INSERT INTO audit_logs (id, action, actor, details, justification, ip_address, created_at)
       VALUES (?, ?, ?, ?, ?, ?, datetime('now'))`
    )
    .bind(genId(), action, actor, details, justification, ip)
    .run();
}

// ─── Helper: criar as 41 fases para um projeto ─────────────────────────────

async function seedPhases(db: D1Database, projectId: string) {
  const stmt = db.prepare(
    `INSERT INTO project_phases (id, project_id, phase_number, title, status, notes, created_at)
     VALUES (?, ?, ?, ?, 'pending', '', datetime('now'))`
  );

  const batch = PHASE_TITLES.map((title, i) =>
    stmt.bind(genId(), projectId, i, title)
  );

  await db.batch(batch);
}

